import combos from "./../../data-json/combos.json"
import Tarjeta from './../tarjetas-simple-doble/tarjeta.js';

 function Combos( setCarrito, carrito ) {
  return (
    <div className='productos-cont'>

      <h2 id='combos'>COMBOS</h2>

      <div className='combos'>
        {
          combos &&
          combos.map((elemento) => (
            <Tarjeta key={elemento.id} id={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} descripcion={elemento.descripcion} agregarCarrito={agregarCarrito} carrito={carrito} />
          ))
        }
      </div>

    </div>
  )
};




export default Combos;
